import { useEffect, useRef } from 'react';

function HelloIndia() {
  const containerRef = useRef(null);

  useEffect(() => {
    fetch('/src/components/tab.html')
      .then(response => response.text())
      .then(html => {
        if (containerRef.current) {
          containerRef.current.innerHTML = html;
        }
      })
      .catch(error => console.error('Error loading HTML:', error));
  }, []); // 空依赖数组，只在组件挂载时执行

  return <div ref={containerRef}></div>;
}
export default HelloIndia;

// 子组件
import { useState } from 'react';

function ChildComponent({ message, onSendData }) {
  const [inputValue, setInputValue] = useState('');

  const handleSend = () => {
    onSendData(inputValue);
    setInputValue('');
  };

  return (
    <div>
      <h3>子组件</h3>
      <p>父组件传来的消息: {message}</p>
      <input
        value={inputValue}
        onChange={(e) => setInputValue(e.target.value)}
        placeholder="输入要发送给父组件的数据"
      />
      <button onClick={handleSend}>发送给父组件</button>
    </div>
  );
}
export default ChildComponent;

// 父组件
import { useState } from 'react';
import ChildComponent from './ChildComponent';

function ParentComponent() {
  const [message, setMessage] = useState('来自父组件的消息');
  const [childData, setChildData] = useState('');

  const handleChildData = (data) => {
    setChildData(data);
  };

  return (
    <div>
      <h2>父组件</h2>
      <input
        value={message}
        onChange={(e) => setMessage(e.target.value)}
      />
      <p>子组件传来的数据: {childData}</p>
      <ChildComponent message={message} onSendData={handleChildData} />
    </div>
  );
}
export default ParentComponent;

